async def seed_database(db: AsyncSession):
    """Seed the database with real NYX CoreFinLogic data if empty.

    Skips seeding if:
      - LOAD_SEED_DATA=false in environment (production safety)
      - Database already contains datasets (idempotency)
    """
    import os
    from app.config import settings

    # Production safety: seed data is disabled by default in production.
    # Override with LOAD_SEED_DATA=true if explicitly needed.
    app_env = getattr(settings, "APP_ENV", "development")
    load_seed = os.getenv("LOAD_SEED_DATA", "").lower()

    if app_env == "production" and load_seed not in ("true", "1", "yes"):
        logger.warning(
            "Seed data loading BLOCKED in production (APP_ENV=%s). "
            "Set LOAD_SEED_DATA=true to override. Production databases "
            "should not contain demo data.",
            app_env,
        )
        return

    if load_seed in ("false", "0", "no"):
        logger.info("Seed data loading disabled (LOAD_SEED_DATA=%s).", load_seed)
        return

    count_result = await db.execute(select(func.count()).select_from(Dataset))
    if count_result.scalar() > 0:
        logger.info("Database already seeded.")
        return

    logger.info(f"Seeding DB: {len(SEED_TRANSACTIONS)} transactions, {len(SEED_REVENUE)} revenue items, {len(SEED_BUDGET)} budget lines")

    ds = Dataset(
        name=f"Reports.xlsx ({settings.COMPANY_NAME})",
        original_filename="Reports.xlsx",
        file_type="Transaction Ledger + Revenue + Budget",
        file_size=102731,
        extension="xlsx",
        sheet_count=4,
        record_count=len(SEED_TRANSACTIONS) + len(SEED_REVENUE) + len(SEED_BUDGET),
        status="ready",
        is_seed=True,
        data_source="seed",
        is_active=True,
        period="January 2025",
        currency="GEL",
        company=settings.COMPANY_NAME,
    )
    db.add(ds)
    await db.flush()

    for t in SEED_TRANSACTIONS:
        db.add(Transaction(
            dataset_id=ds.id,
            date=t.get("date",""),
            recorder=t.get("recorder",""),
            acct_dr=t.get("acct_dr",""),
            acct_cr=t.get("acct_cr",""),
            dept=t.get("dept",""),
            counterparty=t.get("counterparty",""),
            cost_class=t.get("cost_class",""),
            type=t.get("type","Expense"),
            amount=float(t.get("amount",0)),
            vat=float(t.get("vat",0)),
            currency="GEL",
            period="January 2025",
            data_source="seed",
        ))

    for r in SEED_REVENUE:
        product_name = r.get("product", "")
        # Skip summary/total rows
        if product_name.lower() in ('итог', 'итого', 'total', ''):
            continue
        category = _classify_revenue_product(product_name)
        db.add(RevenueItem(
            dataset_id=ds.id,
            product=product_name,
            gross=float(r.get("gross",0)),
            vat=float(r.get("vat",0)),
            net=float(r.get("net",0)),
            segment=r.get("segment","Other Revenue"),
            category=category,
            currency="GEL",
            period="January 2025",
            data_source="seed",
        ))

    # ── Seed COGS items from budget category-level data ──────────────
    _COGS_SEED_ITEMS = [
        ("COGS Whsale Petrol (Lari)",  "COGS Wholesale", "COGS Whsale Petrol"),
        ("COGS Whsale Diesel (Lari)",  "COGS Wholesale", "COGS Whsale Diesel"),
        ("COGS Whsale Bitumen (Lari)", "COGS Wholesale", "COGS Whsale Bitumen"),
        ("COGS Retial Petrol (Lari)",  "COGS Retail",    "COGS Retial Petrol"),
        ("COGS Retial Diesel (Lari)",  "COGS Retail",    "COGS Retial Diesel"),
        ("COGS Retial CNG (Lari)",     "COGS Retail",    "COGS Retial CNG"),
        ("COGS Retial LPG (Lari)",     "COGS Retail",    "COGS Retial LPG"),
    ]
    for budget_key, seg, cat in _COGS_SEED_ITEMS:
        cogs_val = float(SEED_BUDGET.get(budget_key, 0))
        if cogs_val > 0:
            db.add(COGSItem(
                dataset_id=ds.id,
                product=budget_key.replace(" (Lari)", ""),
                col6_amount=cogs_val,
                col7310_amount=0.0,
                col8230_amount=0.0,
                total_cogs=cogs_val,
                segment=seg,
                category=cat,
                currency="GEL",
                period="January 2025",
            ))

    # ── Seed G&A and D&A items from transactions ──────────────────
    # Same logic as file_parser._extract_ga_expenses / _extract_da_expenses
    ga_by_account = {}
    da_by_account = {}
    for t in SEED_TRANSACTIONS:
        acct_dr = str(t.get("acct_dr", "")).strip()
        amt = abs(float(t.get("amount", 0)))
        if acct_dr in GA_ACCOUNT_CODES:
            ga_by_account[acct_dr] = ga_by_account.get(acct_dr, 0) + amt
        elif acct_dr in DA_ACCOUNT_CODES:
            da_by_account[acct_dr] = da_by_account.get(acct_dr, 0) + amt

    for code, amount in ga_by_account.items():
        db.add(GAExpenseItem(
            dataset_id=ds.id,
            account_code=code,
            account_name=GA_ACCOUNT_NAMES.get(code, f"G&A ({code})"),
            amount=round(amount, 2),
            currency="GEL",
            period="January 2025",
        ))
    for code, amount in da_by_account.items():
        db.add(GAExpenseItem(
            dataset_id=ds.id,
            account_code=code,
            account_name=DA_ACCOUNT_NAMES.get(code, f"D&A ({code})"),
            amount=round(amount, 2),
            currency="GEL",
            period="January 2025",
        ))

    for k, v in SEED_BUDGET.items():
        cat = "REVENUE" if "Revenue" in k else "COGS" if "COGS" in k else "MARGIN" if "Margin" in k else "OTHER"
        db.add(BudgetLine(
            dataset_id=ds.id,
            line_item=k,
            budget_amount=float(v),
            currency="GEL",
            period="January 2025",
            category=cat,
        ))

    db.add(AgentMemory(memory_type="system_init", importance=10,
        content=f"Seeded: {len(SEED_TRANSACTIONS)} transactions, {len(SEED_REVENUE)} revenue products, {len(SEED_BUDGET)} budget lines. Period: January 2025. Company: {settings.COMPANY_NAME}."))
    db.add(AgentMemory(memory_type="critical_alert", importance=10,
        content="CRITICAL: Wholesale gross margin is NEGATIVE (Gr. Margin Wholesale: -2,084,604 GEL). Revenue Wholesale ₾23.3M vs COGS Wholesale ₾25.4M. Requires urgent pricing review."))

    await db.commit()
    logger.info("Seed complete.")

    # ── Multi-Period Data Generation (Feb-Dec 2025) ─────────────
    await _seed_multi_period(db, ds.id)


async def _seed_multi_period(db: AsyncSession, base_dataset_id: int):
    """Generate 11 additional months (Feb-Dec 2025) of financial data
    with realistic seasonality for a Georgian petroleum company."""
    import random

    # Seasonal multipliers for fuel distribution (higher in winter)
    SEASONALITY = {
        2: 0.92, 3: 0.85, 4: 0.78, 5: 0.75, 6: 0.72,
        7: 0.70, 8: 0.73, 9: 0.82, 10: 0.90, 11: 0.95, 12: 1.05,
    }
    MONTHS = {
        2: 'February', 3: 'March', 4: 'April', 5: 'May', 6: 'June',
        7: 'July', 8: 'August', 9: 'September', 10: 'October',
        11: 'November', 12: 'December',
    }

    existing = await db.execute(
        select(func.count(Dataset.id)).where(Dataset.period == 'February 2025')
    )
    if existing.scalar() > 0:
        logger.info("Multi-period data already seeded, skipping.")
        return

    total_txn = 0
    total_rev = 0

    for month_num, month_name in MONTHS.items():
        period = f"{month_name} 2025"
        season = SEASONALITY[month_num]
        random.seed(month_num * 42)
        noise = lambda: random.uniform(0.88, 1.12)

        ds = Dataset(
            name=f"Reports.xlsx ({settings.COMPANY_NAME} - {month_name} 2025)",
            file_type="xlsx", period=period, currency="GEL",
            status="parsed", company=settings.COMPANY_NAME, is_seed=True,
        )
        db.add(ds)
        await db.flush()

        for txn in SEED_TRANSACTIONS:
            base_amt = txn.get('amount', 0)
            adj_amt = round(base_amt * season * noise(), 2)
            day_num = min(int(txn.get('date', '01.01.2025')[:2]), 28)
            db.add(Transaction(
                dataset_id=ds.id, date=f"{day_num:02d}.{month_num:02d}.2025",
                recorder=txn.get('recorder', ''), acct_dr=txn.get('acct_dr', ''),
                acct_cr=txn.get('acct_cr', ''), dept=txn.get('dept', ''),
                counterparty=txn.get('counterparty', ''),
                cost_class=txn.get('cost_class', ''), type=txn.get('type', 'Expense'),
                amount=adj_amt, vat=round((txn.get('vat', 0) or 0) * season * noise(), 2),
                currency='GEL', period=period,
            ))
            total_txn += 1

        for rev in SEED_REVENUE:
            gross = round((rev.get('gross', 0) or 0) * season * noise(), 2)
            vat_amt = round((rev.get('vat', 0) or 0) * season * noise(), 2)
            db.add(RevenueItem(
                dataset_id=ds.id, product=rev.get('product', ''),
                gross=gross, vat=vat_amt, net=round(gross - vat_amt, 2),
                segment=rev.get('segment', ''),
                category=_classify_revenue_product(rev.get('product', '')),
                currency='GEL', period=period,
            ))
            total_rev += 1

        for k, v in SEED_BUDGET.items():
            cat = "REVENUE" if "Revenue" in k else "COGS" if "COGS" in k else "MARGIN" if "Margin" in k else "OTHER"
            db.add(BudgetLine(
                dataset_id=ds.id, line_item=k, budget_amount=float(v),
                actual_amount=round(float(v) * season * noise(), 2),
                currency="GEL", period=period, category=cat,
            ))

        if month_num % 3 == 0:
            await db.flush()

    await db.commit()
    logger.info(f"Multi-period seed: 11 months, {total_txn} txn, {total_rev} rev items.")
